Role Descricao Permissoes <code>admin</code> Administrador completo Tudo: CRUD operadores, agents, tasks, listeners, plugins, config <code>operator</code> Operador padrao Gerenciar agents, criar tasks, visualizar resultados <code>viewer</code> Somente leitura Visualizar agents, tasks e resultados <p>Admin sempre tem acesso, independente da lista de roles configurada:</p> <pre><code>// pkg/auth/rbac.go
func RequireRole(roles ...string) func(http.Handler) http.Handler {
    allowed := make(map[string]bool, len(roles))
    for _, r := range roles { allowed[r] = true }
    allowed[RoleAdmin] = true // admin sempre permitido

    return func(next http.Handler) http.Handler {
        return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
            claims := ClaimsFromContext(r.Context())
            if claims == nil {
                http.Error(w, "Forbidden: no credentials", 403)
                return
            }
            if !allowed[claims.Role] {
                http.Error(w, "Forbidden: insufficient role", 403)
                return
            }
            next.ServeHTTP(w, r)
        })
    }
}
